"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[2326],{71106(n,r,t){t.r(r),t.d(r,{assets:()=>e,contentTitle:()=>a,default:()=>i,frontMatter:()=>l,metadata:()=>c,toc:()=>o});const c=JSON.parse('{"id":"cpp17/clamp-gcd-lcm","title":"std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)","description":"C++17 std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp17/56-clamp-gcd-lcm.md","sourceDirName":"cpp17","slug":"/cpp17/56-clamp-gcd-lcm","permalink":"/LearnModernCpp/docs/cpp17/56-clamp-gcd-lcm","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp17","permalink":"/LearnModernCpp/docs/tags/cpp-17"},{"inline":true,"label":"clamp_gcd_lcm","permalink":"/LearnModernCpp/docs/tags/clamp-gcd-lcm"}],"version":"current","sidebarPosition":57,"frontMatter":{"sidebar_position":57,"slug":"56-clamp-gcd-lcm","title":"std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)","description":"C++17 std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177) \u6559\u5b66\u793a\u4f8b","tags":["cpp17","clamp_gcd_lcm"]},"sidebar":"docs","previous":{"title":"\u5e76\u884c\u6267\u884c\u7b56\u7565 (Parallel Execution Policies)","permalink":"/LearnModernCpp/docs/cpp17/55-parallel-algorithms"},"next":{"title":"C++17 \u5c5e\u6027 [[nodiscard]]\u3001[[maybe_unused]]\u3001[[fallthrough]]","permalink":"/LearnModernCpp/docs/cpp17/90-attributes"}}');var d=t(74848),s=t(28453);const l={sidebar_position:57,slug:"56-clamp-gcd-lcm",title:"std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)",description:"C++17 std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177) \u6559\u5b66\u793a\u4f8b",tags:["cpp17","clamp_gcd_lcm"]},a="std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)",e={},o=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function m(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,d.jsxs)(d.Fragment,{children:[(0,d.jsx)(r.header,{children:(0,d.jsx)(r.h1,{id:"stdclampstdgcdstdlcm-\u6570\u5b66\u5de5\u5177",children:"std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)"})}),"\n",(0,d.jsx)(r.p,{children:"C++17 \u6807\u51c6\u5f15\u5165\u7684 std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,d.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,d.jsx)(r.pre,{children:(0,d.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp17/56_clamp_gcd_lcm.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)\r\n * \u6240\u5c5e\u6807\u51c6: C++17\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++17 \u65b0\u589e\u7684\u4e09\u4e2a\u5b9e\u7528\u6570\u5b66\u51fd\u6570\uff1a\r\n *          - std::clamp(value, lo, hi) \u2014\u2014 \u5c06\u503c\u94b3\u5236\u5728 [lo, hi] \u8303\u56f4\u5185\r\n *          - std::gcd(a, b) \u2014\u2014 \u8ba1\u7b97\u6700\u5927\u516c\u7ea6\u6570 (Greatest Common Divisor)\r\n *          - std::lcm(a, b) \u2014\u2014 \u8ba1\u7b97\u6700\u5c0f\u516c\u500d\u6570 (Least Common Multiple)\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u8fd9\u4e9b\u662f\u975e\u5e38\u5e38\u7528\u7684\u6570\u5b66\u64cd\u4f5c\uff0c\u4e4b\u524d\u9700\u8981\u81ea\u5df1\u5b9e\u73b0\u6216\u4f7f\u7528\r\n *              \u975e\u6807\u51c6\u7684\u6269\u5c55\u3002C++17 \u5c06\u5b83\u4eec\u7eb3\u5165\u6807\u51c6\u5e93\uff0c\u65b9\u4fbf\u4f7f\u7528\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - clamp \u5728 <algorithm> \u4e2d\uff0cgcd/lcm \u5728 <numeric> \u4e2d\r\n *   - clamp(v, lo, hi): v < lo \u8fd4\u56de lo\uff0cv > hi \u8fd4\u56de hi\uff0c\u5426\u5219\u8fd4\u56de v\r\n *   - gcd/lcm \u53ea\u63a5\u53d7\u6574\u6570\u7c7b\u578b\uff0c\u7ed3\u679c\u603b\u662f\u975e\u8d1f\u6570\r\n *   - gcd(0, 0) = 0\uff0cgcd(a, 0) = |a|\r\n *   - lcm(a, 0) = 0\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <algorithm>  // std::clamp\r\n#include <numeric>    // std::gcd, std::lcm\r\n#include <vector>\r\n#include <string>\r\n#include <cmath>\r\n#include <cassert>\r\n#include <array>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // ---- std::clamp ----\r\n    std::cout << "== std::clamp ==\\n";\r\n\r\n    // 1. \u57fa\u672c\u7528\u6cd5\r\n    int value = 15;\r\n    int lo = 0, hi = 10;\r\n    int clamped = std::clamp(value, lo, hi);\r\n    std::cout << "clamp(15, 0, 10) = " << clamped << "\\n";\r\n    std::cout << "clamp(5, 0, 10)  = " << std::clamp(5, 0, 10) << "\\n";\r\n    std::cout << "clamp(-3, 0, 10) = " << std::clamp(-3, 0, 10) << "\\n";\r\n\r\n    // 2. \u6d6e\u70b9\u6570 clamp\r\n    std::cout << "clamp(3.7, 0.0, 1.0) = " << std::clamp(3.7, 0.0, 1.0) << "\\n";\r\n    std::cout << "clamp(-0.5, 0.0, 1.0) = " << std::clamp(-0.5, 0.0, 1.0) << "\\n";\r\n    std::cout << "clamp(0.5, 0.0, 1.0) = " << std::clamp(0.5, 0.0, 1.0) << "\\n";\r\n\r\n    // ---- std::gcd ----\r\n    std::cout << "\\n== std::gcd ==\\n";\r\n\r\n    std::cout << "gcd(12, 8)  = " << std::gcd(12, 8) << "\\n";   // 4\r\n    std::cout << "gcd(100, 75) = " << std::gcd(100, 75) << "\\n"; // 25\r\n    std::cout << "gcd(17, 13) = " << std::gcd(17, 13) << "\\n";   // 1 (\u4e92\u8d28)\r\n    std::cout << "gcd(0, 5)   = " << std::gcd(0, 5) << "\\n";     // 5\r\n    std::cout << "gcd(0, 0)   = " << std::gcd(0, 0) << "\\n";     // 0\r\n    std::cout << "gcd(-12, 8) = " << std::gcd(-12, 8) << "\\n";   // 4 (\u603b\u662f\u975e\u8d1f)\r\n\r\n    // ---- std::lcm ----\r\n    std::cout << "\\n== std::lcm ==\\n";\r\n\r\n    std::cout << "lcm(4, 6)   = " << std::lcm(4, 6) << "\\n";    // 12\r\n    std::cout << "lcm(12, 8)  = " << std::lcm(12, 8) << "\\n";   // 24\r\n    std::cout << "lcm(7, 5)   = " << std::lcm(7, 5) << "\\n";    // 35\r\n    std::cout << "lcm(0, 5)   = " << std::lcm(0, 5) << "\\n";    // 0\r\n    std::cout << "lcm(3, 3)   = " << std::lcm(3, 3) << "\\n";    // 3\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. clamp \u5e94\u7528\uff1a\u989c\u8272\u503c\u9650\u5236\r\nstruct Color {\r\n    int r, g, b;\r\n\r\n    Color clamp_to_valid() const {\r\n        return {\r\n            std::clamp(r, 0, 255),\r\n            std::clamp(g, 0, 255),\r\n            std::clamp(b, 0, 255)\r\n        };\r\n    }\r\n\r\n    void print() const {\r\n        std::cout << "RGB(" << r << ", " << g << ", " << b << ")";\r\n    }\r\n};\r\n\r\n// 2. clamp \u5e94\u7528\uff1a\u6e38\u620f\u4e2d\u7684\u503c\u9650\u5236\r\nstruct Player {\r\n    int hp;\r\n    int max_hp = 100;\r\n\r\n    void take_damage(int damage) {\r\n        hp = std::clamp(hp - damage, 0, max_hp);\r\n    }\r\n\r\n    void heal(int amount) {\r\n        hp = std::clamp(hp + amount, 0, max_hp);\r\n    }\r\n};\r\n\r\n// 3. gcd \u5e94\u7528\uff1a\u5206\u6570\u5316\u7b80\r\nstruct Fraction {\r\n    int numerator;\r\n    int denominator;\r\n\r\n    Fraction simplify() const {\r\n        int g = std::gcd(std::abs(numerator), std::abs(denominator));\r\n        if (g == 0) return {0, 1};\r\n        int sign = (denominator < 0) ? -1 : 1;\r\n        return {sign * numerator / g, sign * denominator / g};\r\n    }\r\n\r\n    void print() const {\r\n        std::cout << numerator << "/" << denominator;\r\n    }\r\n\r\n    // \u5206\u6570\u52a0\u6cd5\uff08\u5229\u7528 lcm \u6c42\u901a\u5206\u6bcd\uff09\r\n    Fraction operator+(const Fraction& other) const {\r\n        int common = std::lcm(denominator, other.denominator);\r\n        int new_num = numerator * (common / denominator) +\r\n                      other.numerator * (common / other.denominator);\r\n        return Fraction{new_num, common}.simplify();\r\n    }\r\n};\r\n\r\n// 4. \u591a\u4e2a\u6570\u7684 gcd/lcm\uff08\u4f7f\u7528\u6298\u53e0\u8868\u8fbe\u5f0f\uff09\r\ntemplate<typename T, typename... Rest>\r\nauto multi_gcd(T first, Rest... rest) {\r\n    if constexpr (sizeof...(rest) == 0) {\r\n        return first;\r\n    } else {\r\n        return std::gcd(first, multi_gcd(rest...));\r\n    }\r\n}\r\n\r\nint gcd_of_vector(const std::vector<int>& v) {\r\n    int result = v[0];\r\n    for (size_t i = 1; i < v.size(); ++i) {\r\n        result = std::gcd(result, v[i]);\r\n    }\r\n    return result;\r\n}\r\n\r\nlong long lcm_of_vector(const std::vector<int>& v) {\r\n    long long result = v[0];\r\n    for (size_t i = 1; i < v.size(); ++i) {\r\n        result = std::lcm(result, static_cast<long long>(v[i]));\r\n    }\r\n    return result;\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // \u989c\u8272\u94b3\u5236\r\n    Color raw{300, -20, 128};\r\n    std::cout << "\u539f\u59cb\u989c\u8272: ";\r\n    raw.print();\r\n    Color valid = raw.clamp_to_valid();\r\n    std::cout << " -> \u94b3\u5236\u540e: ";\r\n    valid.print();\r\n    std::cout << "\\n";\r\n\r\n    // \u6e38\u620fHP\u7ba1\u7406\r\n    Player player{80};\r\n    std::cout << "\\n\u73a9\u5bb6 HP: " << player.hp;\r\n    player.take_damage(30);\r\n    std::cout << " -> \u53d7\u4f2430: " << player.hp;\r\n    player.heal(100);\r\n    std::cout << " -> \u6cbb\u7597100: " << player.hp;\r\n    player.take_damage(999);\r\n    std::cout << " -> \u53d7\u4f24999: " << player.hp << "\\n";\r\n\r\n    // \u5206\u6570\u5316\u7b80\r\n    std::cout << "\\n\u5206\u6570\u5316\u7b80:\\n";\r\n    Fraction f1{12, 8};\r\n    std::cout << "  ";\r\n    f1.print();\r\n    std::cout << " = ";\r\n    f1.simplify().print();\r\n    std::cout << "\\n";\r\n\r\n    Fraction f2{-6, 9};\r\n    std::cout << "  ";\r\n    f2.print();\r\n    std::cout << " = ";\r\n    f2.simplify().print();\r\n    std::cout << "\\n";\r\n\r\n    // \u5206\u6570\u52a0\u6cd5\uff08\u5229\u7528 lcm \u901a\u5206\uff09\r\n    Fraction a{1, 3}, b{1, 4};\r\n    auto c = a + b;\r\n    std::cout << "  ";\r\n    a.print();\r\n    std::cout << " + ";\r\n    b.print();\r\n    std::cout << " = ";\r\n    c.print();\r\n    std::cout << "\\n";\r\n\r\n    // \u591a\u4e2a\u6570\u7684 gcd/lcm\r\n    std::vector<int> nums{12, 18, 24, 36};\r\n    std::cout << "\\n\u591a\u4e2a\u6570\u7684 gcd{12,18,24,36} = " << gcd_of_vector(nums) << "\\n";\r\n    std::cout << "multi_gcd(12,18,24,36) = " << multi_gcd(12, 18, 24, 36) << "\\n";\r\n    std::cout << "\u591a\u4e2a\u6570\u7684 lcm{12,18,24,36} = " << lcm_of_vector(nums) << "\\n";\r\n\r\n    // clamp \u6279\u91cf\u64cd\u4f5c\r\n    std::vector<int> values{-5, 3, 7, 15, 20, -1, 8};\r\n    std::cout << "\\n\u6279\u91cf clamp [0, 10]: ";\r\n    for (int v : values) {\r\n        std::cout << std::clamp(v, 0, 10) << " ";\r\n    }\r\n    std::cout << "\\n";\r\n\r\n    // \u4e0e clamp \u7b49\u4ef7\u7684 min/max \u5199\u6cd5\u5bf9\u6bd4\r\n    int x = 15;\r\n    // C++14 \u5199\u6cd5\uff1a\r\n    int old_way = std::min(std::max(x, 0), 10);\r\n    // C++17 \u5199\u6cd5\uff1a\r\n    int new_way = std::clamp(x, 0, 10);\r\n    std::cout << "\\nmin(max(15,0),10) = " << old_way << "\\n";\r\n    std::cout << "clamp(15, 0, 10)  = " << new_way << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9 / \u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u9631 1: clamp \u8981\u6c42 lo <= hi\uff0c\u5426\u5219\u662f UB\r\n    // std::clamp(5, 10, 0);  // UB\uff01lo=10 > hi=0\r\n    std::cout << "\u9677\u96311 - clamp \u8981\u6c42 lo <= hi\uff0c\u5426\u5219\u672a\u5b9a\u4e49\u884c\u4e3a\\n";\r\n\r\n    // \u9677\u9631 2: clamp \u8fd4\u56de\u7684\u662f\u5f15\u7528\uff08const T&\uff09\r\n    //   \u5982\u679c\u4f20\u5165\u4e34\u65f6\u503c\uff0c\u6ce8\u610f\u751f\u547d\u5468\u671f\r\n    int a = 5;\r\n    const int& ref = std::clamp(a, 0, 10);  // OK: a \u8fd8\u6d3b\u7740\r\n    std::cout << "\u9677\u96312 - clamp \u8fd4\u56de const \u5f15\u7528: " << ref << "\\n";\r\n    // const int& bad = std::clamp(5, 0, 10);  // \u5371\u9669\uff1a\u7ed1\u5b9a\u5230\u4e34\u65f6\u503c\r\n    // \u4f46\u5b9e\u9645\u4e0a\u7f16\u8bd1\u5668\u901a\u5e38\u4f1a\u5ef6\u957f\u4e34\u65f6\u503c\u751f\u547d\u5468\u671f\r\n\r\n    // \u9677\u9631 3: gcd/lcm \u53ea\u63a5\u53d7\u6574\u6570\u7c7b\u578b\r\n    // std::gcd(3.14, 2.0);  // \u7f16\u8bd1\u9519\u8bef\uff01\r\n    std::cout << "\u9677\u96313 - gcd/lcm \u53ea\u63a5\u53d7\u6574\u6570\u7c7b\u578b\\n";\r\n\r\n    // \u9677\u9631 4: lcm \u53ef\u80fd\u6ea2\u51fa\r\n    //   lcm(a, b) = |a| / gcd(a,b) * |b|\r\n    //   \u5927\u6570\u7684 lcm \u53ef\u80fd\u8d85\u8fc7 int \u8303\u56f4\r\n    std::cout << "\u9677\u96314 - lcm \u53ef\u80fd\u6ea2\u51fa! lcm(\u5927\u6570, \u5927\u6570) \u9700\u8981\u7528 long long\\n";\r\n    long long big_lcm = std::lcm(100000LL, 99999LL);\r\n    std::cout << "  lcm(100000, 99999) = " << big_lcm << "\\n";\r\n\r\n    // \u9677\u9631 5: gcd \u7ed3\u679c\u603b\u662f\u975e\u8d1f\u7684\r\n    std::cout << "\u9677\u96315 - gcd(-12, -8) = " << std::gcd(-12, -8) << " (\u603b\u662f\u975e\u8d1f)\\n";\r\n\r\n    // \u9677\u9631 6: clamp \u4e0e NaN\r\n    //   \u6d6e\u70b9\u6570 NaN \u7684\u6bd4\u8f83\u884c\u4e3a\u7279\u6b8a\r\n    //   clamp(NaN, 0.0, 1.0) \u7684\u7ed3\u679c\u662f UB\r\n    std::cout << "\u9677\u96316 - clamp(NaN, lo, hi) \u662f\u672a\u5b9a\u4e49\u884c\u4e3a\\n";\r\n\r\n    // \u9677\u9631 7: gcd(0, 0) = 0 \u662f\u7279\u6b8a\u60c5\u51b5\r\n    std::cout << "\u9677\u96317 - gcd(0,0) = " << std::gcd(0, 0) << " (\u6570\u5b66\u4e0a\u672a\u5b9a\u4e49\uff0cC++\u5b9a\u4e49\u4e3a0)\\n";\r\n\r\n    // \u9677\u9631 8: clamp \u7684\u7c7b\u578b\u8981\u4e00\u81f4\r\n    // std::clamp(5, 0L, 10L);  // \u53ef\u80fd\u7f16\u8bd1\u9519\u8bef\uff1aint \u548c long \u4e0d\u5339\u914d\r\n    // \u89e3\u51b3\uff1a\u663e\u5f0f\u8f6c\u6362\r\n    auto result = std::clamp(5L, 0L, 10L);\r\n    std::cout << "\u9677\u96318 - clamp \u4e09\u4e2a\u53c2\u6570\u7c7b\u578b\u5fc5\u987b\u4e00\u81f4: " << result << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== std::clamp / gcd / lcm - C++17 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,d.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,d.jsxs)(r.ul,{children:["\n",(0,d.jsx)(r.li,{children:(0,d.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/algorithm/clamp",children:"cppreference: std::clamp\u3001std::gcd\u3001std::lcm (\u6570\u5b66\u5de5\u5177)"})}),"\n"]})]})}function i(n={}){const{wrapper:r}={...(0,s.R)(),...n.components};return r?(0,d.jsx)(r,{...n,children:(0,d.jsx)(m,{...n})}):m(n)}},28453(n,r,t){t.d(r,{R:()=>l,x:()=>a});var c=t(96540);const d={},s=c.createContext(d);function l(n){const r=c.useContext(s);return c.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function a(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(d):n.components||d:l(n.components),c.createElement(s.Provider,{value:r},n.children)}}}]);